# ASCII Text

Three.js 3D text rendered as an ASCII character grid via custom AsciiFilter class, with wave vertex shader animation and mouse-driven rotation.

## Use when
- Displaying a hero headline with a retro ASCII grid aesthetic.
- Adding a 3D interactive text effect that rotates toward the cursor.
- Creating a dark-theme section title with wave animation.

## Stack
- Framework: react
- Libraries: three

## Install
```bash
npm install three @types/three
```

## Component — ascii-text.tsx
```tsx
// Component ported and enhanced from https://codepen.io/JuanFuentes/pen/eYEeoyE
import { useRef, useEffect } from 'react';
import * as THREE from 'three';

const vertexShader = `
varying vec2 vUv;
uniform float uTime;
uniform float mouse;
uniform float uEnableWaves;
void main() {
    vUv = uv;
    float time = uTime * 5.;
    float waveFactor = uEnableWaves;
    vec3 transformed = position;
    transformed.x += sin(time + position.y) * 0.5 * waveFactor;
    transformed.y += cos(time + position.z) * 0.15 * waveFactor;
    transformed.z += sin(time + position.x) * waveFactor;
    gl_Position = projectionMatrix * modelViewMatrix * vec4(transformed, 1.0);
}
`;

const fragmentShader = `
varying vec2 vUv;
uniform float mouse;
uniform float uTime;
uniform sampler2D uTexture;
void main() {
    float time = uTime;
    vec2 pos = vUv;
    float r = texture2D(uTexture, pos + cos(time * 2. - time + pos.x) * .01).r;
    float g = texture2D(uTexture, pos + tan(time * .5 + pos.x - time) * .01).g;
    float b = texture2D(uTexture, pos - cos(time * 2. + time + pos.y) * .01).b;
    float a = texture2D(uTexture, pos).a;
    gl_FragColor = vec4(r, g, b, a);
}
`;

function map(n: number, start: number, stop: number, start2: number, stop2: number) {
  return ((n - start) / (stop - start)) * (stop2 - start2) + start2;
}

const PX_RATIO = typeof window !== 'undefined' ? window.devicePixelRatio : 1;

class AsciiFilter {
  renderer: THREE.WebGLRenderer; domElement: HTMLDivElement; pre: HTMLPreElement;
  canvas: HTMLCanvasElement; context: CanvasRenderingContext2D | null;
  deg: number; invert: boolean; fontSize: number; fontFamily: string; charset: string;
  width: number = 0; height: number = 0;
  center: { x: number; y: number } = { x: 0, y: 0 };
  mouse: { x: number; y: number } = { x: 0, y: 0 };
  cols: number = 0; rows: number = 0;

  constructor(renderer: THREE.WebGLRenderer, { fontSize, fontFamily, charset, invert }: { fontSize?: number; fontFamily?: string; charset?: string; invert?: boolean } = {}) {
    this.renderer = renderer;
    this.domElement = document.createElement('div');
    this.domElement.style.cssText = 'position:absolute;top:0;left:0;width:100%;height:100%;';
    this.pre = document.createElement('pre');
    this.domElement.appendChild(this.pre);
    this.canvas = document.createElement('canvas');
    this.context = this.canvas.getContext('2d');
    this.domElement.appendChild(this.canvas);
    this.deg = 0; this.invert = invert ?? true;
    this.fontSize = fontSize ?? 12; this.fontFamily = fontFamily ?? "'Courier New', monospace";
    this.charset = charset ?? " .'`^\",:;Il!i~+_-?][}{1)(|/tfjrxnuvczXYUJCLQ0OZmwqpdbkhao*#MW&8%B@$";
    if (this.context) this.context.imageSmoothingEnabled = false;
    this.onMouseMove = this.onMouseMove.bind(this);
    document.addEventListener('mousemove', this.onMouseMove);
  }

  setSize(width: number, height: number) {
    this.width = width; this.height = height;
    this.renderer.setSize(width, height); this.reset();
    this.center = { x: width / 2, y: height / 2 }; this.mouse = { ...this.center };
  }

  reset() {
    if (this.context) {
      this.context.font = `${this.fontSize}px ${this.fontFamily}`;
      const charWidth = this.context.measureText('A').width;
      this.cols = Math.floor(this.width / (this.fontSize * (charWidth / this.fontSize)));
      this.rows = Math.floor(this.height / this.fontSize);
      this.canvas.width = this.cols; this.canvas.height = this.rows;
      Object.assign(this.pre.style, { fontFamily: this.fontFamily, fontSize: `${this.fontSize}px`, margin: '0', padding: '0', lineHeight: '1em', position: 'absolute', left: '50%', top: '50%', transform: 'translate(-50%, -50%)', zIndex: '9', backgroundAttachment: 'fixed', mixBlendMode: 'difference' });
    }
  }

  render(scene: THREE.Scene, camera: THREE.Camera) {
    this.renderer.render(scene, camera);
    const w = this.canvas.width; const h = this.canvas.height;
    if (this.context) {
      this.context.clearRect(0, 0, w, h);
      if (w && h) this.context.drawImage(this.renderer.domElement, 0, 0, w, h);
      this.asciify(this.context, w, h); this.hue();
    }
  }

  onMouseMove(e: MouseEvent) { this.mouse = { x: e.clientX * PX_RATIO, y: e.clientY * PX_RATIO }; }
  get dx() { return this.mouse.x - this.center.x; }
  get dy() { return this.mouse.y - this.center.y; }

  hue() {
    const deg = (Math.atan2(this.dy, this.dx) * 180) / Math.PI;
    this.deg += (deg - this.deg) * 0.075;
    this.domElement.style.filter = `hue-rotate(${this.deg.toFixed(1)}deg)`;
  }

  asciify(ctx: CanvasRenderingContext2D, w: number, h: number) {
    if (w && h) {
      const imgData = ctx.getImageData(0, 0, w, h).data;
      let str = '';
      for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) {
          const i = x * 4 + y * 4 * w;
          const [r, g, b, a] = [imgData[i], imgData[i + 1], imgData[i + 2], imgData[i + 3]];
          if (a === 0) { str += ' '; continue; }
          let gray = (0.3 * r + 0.6 * g + 0.1 * b) / 255;
          let idx = Math.floor((1 - gray) * (this.charset.length - 1));
          if (this.invert) idx = this.charset.length - idx - 1;
          str += this.charset[idx];
        }
        str += '\n';
      }
      this.pre.innerHTML = str;
    }
  }

  dispose() { document.removeEventListener('mousemove', this.onMouseMove); }
}

interface ASCIITextProps {
  text?: string;
  asciiFontSize?: number;
  textFontSize?: number;
  textColor?: string;
  planeBaseHeight?: number;
  enableWaves?: boolean;
}

export default function ASCIIText({
  text = 'David!',
  asciiFontSize = 8,
  textFontSize = 200,
  textColor = '#fdf9f3',
  planeBaseHeight = 8,
  enableWaves = true
}: ASCIITextProps) {
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!containerRef.current) return;
    const container = containerRef.current;
    const { width, height } = container.getBoundingClientRect();

    const camera = new THREE.PerspectiveCamera(45, width / height, 1, 1000);
    camera.position.z = 30;
    const scene = new THREE.Scene();

    // Create text canvas texture
    const textCanvas = document.createElement('canvas');
    const textCtx = textCanvas.getContext('2d')!;
    textCtx.font = `600 ${textFontSize}px IBM Plex Mono`;
    const metrics = textCtx.measureText(text);
    textCanvas.width = Math.ceil(metrics.width) + 20;
    textCanvas.height = Math.ceil(metrics.actualBoundingBoxAscent + metrics.actualBoundingBoxDescent) + 20;
    textCtx.font = `600 ${textFontSize}px IBM Plex Mono`;
    textCtx.fillStyle = textColor;
    textCtx.fillText(text, 10, 10 + metrics.actualBoundingBoxAscent);

    const texture = new THREE.CanvasTexture(textCanvas);
    texture.minFilter = THREE.NearestFilter;
    const textAspect = textCanvas.width / textCanvas.height;
    const geometry = new THREE.PlaneGeometry(planeBaseHeight * textAspect, planeBaseHeight, 36, 36);
    const material = new THREE.ShaderMaterial({
      vertexShader, fragmentShader, transparent: true,
      uniforms: { uTime: { value: 0 }, mouse: { value: 1.0 }, uTexture: { value: texture }, uEnableWaves: { value: enableWaves ? 1.0 : 0.0 } }
    });
    const mesh = new THREE.Mesh(geometry, material);
    scene.add(mesh);

    const renderer = new THREE.WebGLRenderer({ antialias: false, alpha: true });
    renderer.setPixelRatio(1); renderer.setClearColor(0x000000, 0);
    const filter = new AsciiFilter(renderer, { fontFamily: 'IBM Plex Mono', fontSize: asciiFontSize, invert: true });
    container.appendChild(filter.domElement);
    filter.setSize(width, height);

    let mouse = { x: 0, y: 0 };
    const onMouseMove = (evt: MouseEvent | TouchEvent) => {
      const e = (evt as TouchEvent).touches ? (evt as TouchEvent).touches[0] : (evt as MouseEvent);
      const bounds = container.getBoundingClientRect();
      mouse = { x: e.clientX - bounds.left, y: e.clientY - bounds.top };
    };
    container.addEventListener('mousemove', onMouseMove);
    container.addEventListener('touchmove', onMouseMove);

    let frameId: number;
    const animate = () => {
      frameId = requestAnimationFrame(animate);
      const time = new Date().getTime() * 0.001;
      texture.needsUpdate = true;
      (mesh.material as THREE.ShaderMaterial).uniforms.uTime.value = Math.sin(time);
      const x = map(mouse.y, 0, height, 0.5, -0.5);
      const y = map(mouse.x, 0, width, -0.5, 0.5);
      mesh.rotation.x += (x - mesh.rotation.x) * 0.05;
      mesh.rotation.y += (y - mesh.rotation.y) * 0.05;
      filter.render(scene, camera);
    };
    animate();

    return () => {
      cancelAnimationFrame(frameId);
      filter.dispose();
      if (container.contains(filter.domElement)) container.removeChild(filter.domElement);
      container.removeEventListener('mousemove', onMouseMove);
      container.removeEventListener('touchmove', onMouseMove);
      geometry.dispose(); material.dispose(); renderer.dispose();
    };
  }, [text, asciiFontSize, textFontSize, textColor, planeBaseHeight, enableWaves]);

  return (
    <div ref={containerRef} style={{ position: 'absolute', width: '100%', height: '100%', overflow: 'hidden' }}>
      <style>{`@import url('https://fonts.googleapis.com/css2?family=IBM+Plex+Mono:wght@500&display=swap');`}</style>
    </div>
  );
}
```

## Notes
- Component uses IBM Plex Mono font (loaded from Google Fonts via `@import`).
- Container must have explicit dimensions and `position: relative` or `absolute`.
- The ASCII grid is rendered into a `<pre>` element with `mix-blend-mode: difference`, producing a gradient hue-rotation effect on mouse movement.

## Demo
```tsx
import ASCIIText from './Component';

export default function App() {
  return (
    <div style={{ width: '100%', height: '600px', position: 'relative', background: '#1A1A1B' }}>
      <ASCIIText text="ASCII_WAVE" enableWaves={true} asciiFontSize={8} />
    </div>
  );
}
```
